-- W1.6 questions batch 663/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-e0adf6cd-moex-00175', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-110-856e6567', 'sub-aboriginal-e0adf6cd-01', NULL, 'essay', '「圖騰」可謂是廣泛符號的一種，洞察人類自古以來，許多原住民族傳統
習俗，常藉用大自然中的動、植物及天空星體為其圖騰（如百步蛇、百
合花、太陽等），展現該族群所特有的符號文化內涵，並期能從中獲得保
護、勇氣和超人的力量，足見符號與人類關係之密切。事實上，學校教
育的過程，宛若符號互動的歷程，請列舉五項符號的功能，並分別列舉
一個校園符號說明之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "b1363bb64c7f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "403", "s": "1003", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00176', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-110-856e6567', 'sub-aboriginal-e0adf6cd-01', NULL, 'essay', '哲學與教育關係密切，因越經得起驗證的哲學思維往往對教育實務的影
響越大。如美國現代教育哲學家杜威（John Dewey, 1859~1952）主張知
識之學習需理性與經驗交互作用，成效較佳；而早於二千多年前孔子即
曾謂：「學而不思則罔，思而不學則殆」；兩位哲學家的前述智慧，留給
後人奉為圭臬，請列舉學烹飪、打球、書法、游泳、開車此五個實例以
驗證論述其哲理。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "b1363bb64c7f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "403", "s": "1003", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00177', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-110-856e6567', 'sub-aboriginal-e0adf6cd-01', NULL, 'essay', '曾有「某高中學生甲因『善心』協助行動不便學生乙，從樓上揹到樓下，
『過程』中因沒電梯且樓梯因下雨濕滑，致使學生乙摔傷而送醫不治」，因
「結果」很不好，導致法院對當時僅高中生的「學生甲」是否判賠合理金
額，引發法界與一般社會嚴重爭辯之案例。洞察法令與道德是維繫人類社
會之最主要規範，而學校教育根本目的之一，在於培育學生對人類行為具
有法令與道德之「是非善惡」判斷力；然而，該判斷力之依據，主要以行
為之動機、過程（情境）與結果為規準，如以前述「案例」為例，試申論：
⑴過度偏重動機⑵過度偏重過程（情境）⑶過度偏重結果，分別易產生什
麼偏差問題？⑷又當如何因應較能客觀做合理判斷呢？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "b1363bb64c7f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "403", "s": "1003", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00178', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-110-856e6567', 'sub-aboriginal-e0adf6cd-01', NULL, 'essay', '試解析老子所謂：「人法地，地法天，天法『道』，『道』法自然」之意涵，
並列舉兩例以申論該思維對學校「因才施教」教育之啟發。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "b1363bb64c7f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "403", "s": "1003", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00179', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-110-236aff17', 'sub-aboriginal-e0adf6cd-02', NULL, 'essay', '語言學習有所謂的關鍵期嗎？雙語發展對個人那些認知能力有益處？
請寫出五項。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "5d9546a57f8c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "403", "s": "1005", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育心理學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00180', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-110-236aff17', 'sub-aboriginal-e0adf6cd-02', NULL, 'essay', '請從訊息處理理論的觀點詳述訊息從出現到被人們永久保存的歷程，分
別說明每個歷程運作方式、特色，以及影響訊息保留之因素。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "5d9546a57f8c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "403", "s": "1005", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育心理學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00181', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-110-236aff17', 'sub-aboriginal-e0adf6cd-02', NULL, 'essay', '四位學生準備期末考，他們對考試抱持以下的想法：
甲生：「期末考花點時間讀，只要不要考最後一名，讓人家覺得我笨就可以了。」
乙生：「我一直想讓自己這科的能力有所提升，考試可以讓我知道那裡要改善。」
丙生：「上次考試沒拿到第一名，這一次我要特別注意老師的命題趨向，打敗對手。」
丁生：「我擔心自己沒有掌握好考試範圍的材料，或因忘記沒有發揮實力。」
請根據目標導向理論（goal orientation theory），指出四位學生的目標類
型，說明各目標類型之特色以及該類型學生典型的學習策略。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "5d9546a57f8c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "403", "s": "1005", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育心理學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00182', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-110-236aff17', 'sub-aboriginal-e0adf6cd-02', NULL, 'essay', '小學五年級的小米一放學就開始玩手機，到了睡覺前才草草寫功課，成
績越來越不理想。媽媽因此與小米約定回家要先做完功課才能玩手機。
但小米屢次破壞規則。這天小米一回家就玩手機一個小時，中間媽媽提
醒小米現在先作功課，但小米持續玩。媽媽於是沒收小米的手機。小米
大聲抗議：「你憑什麼沒收我的手機？」
請詳述「我訊息」的三要素，並用媽媽的身分以「我訊息」回應小米。
另寫出和小米這個年紀的兒童作手機使用約定最重要的三項原則。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "5d9546a57f8c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "403", "s": "1005", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育心理學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00183', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-110-40444de9', 'sub-aboriginal-e0adf6cd-03', NULL, 'essay', '小義接受某標準化推理能力測驗，該測驗的平均數為 45分，標準差為 7
分，小義的原始分數為 38分。將小義的原始分數轉換成各種衍生分數，
以利後續的結果解釋。
請解釋標準化推理能力測驗中「標準化」的意思。（5 分）
小義的 z分數是多少？請解釋此 z分數的意義。（7分）
小義的百分等級是多少？請解釋此百分等級的意義。（7分）
小義的 T分數是多少？（3分）
小義的標準九分數是多少？（3 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "f36419ef3c1d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "403", "s": "1004", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育測驗與統計", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00184', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-110-40444de9', 'sub-aboriginal-e0adf6cd-03', NULL, 'essay', '一實驗中學的校長想了解該校學生的智商是否不同於一般中學生，於是
他從該校學生中隨機抽取 64 名學生接受魏氏智力測驗（平均數=100，
標準差=15），得到平均數為 103。請回答以下問題並進行考驗。
寫出虛無假設與對立假設。（4分）
若α=.05，臨界值應該是多少？（3 分）
請進行假設考驗，計算出數值，並解釋結果。（10 分）
請使用區間估計的方法，計算該校學生真正智商的 95%信賴區間，並
解釋此區間估計的結果與假設考驗的結果是否一致。（8 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "f36419ef3c1d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "403", "s": "1004", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育測驗與統計", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL)
